from defusedxml.lxml import fromstring
from lxml import etree

def process_soap_request(xml_data):
    # Parse the XML with DTD validation disabled for security
    parser = etree.XMLParser(resolve_entities=False, dtd_validation=False, no_network=True)
    
    try:
        # Parse the XML data
        tree = fromstring(xml_data, parser=parser)
        
        # Extract the SOAP envelope and body
        envelope = tree.find('{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
        if envelope is None:
            raise ValueError("Invalid SOAP Envelope")
        
        body = envelope.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if body is None:
            raise ValueError("Invalid SOAP Body")
        
        # Extract and return the message body
        return etree.tostring(body, pretty_print=True).decode('utf-8')
    
    except (etree.XMLSyntaxError, ValueError) as e:
        raise ValueError(f"Error processing SOAP request: {e}")

